import android.content.Context
import android.content.SharedPreferences
import androidx.core.content.edit

class AuthManager private constructor(context: Context) {

    companion object {
        private const val PREF_NAME = "auth_prefs"
        private const val KEY_AUTH_TOKEN = "auth_token"
        private const val KEY_USER_ID = "user_id"
        private const val KEY_IS_LOGGED_IN = "is_logged_in"
        private const val KEY_LOGIN_TIMESTAMP = "login_timestamp"
        private const val KEY_USER_EMAIL = "user_email"
        private const val KEY_USER_DISPLAY_NAME = "user_display_name"

        // Token expiry: 30 days in milliseconds
        private const val TOKEN_EXPIRY_MS = 30L * 24 * 60 * 60 * 1000

        @Volatile
        private var instance: AuthManager? = null

        fun getInstance(context: Context): AuthManager {
            return instance ?: synchronized(this) {
                instance ?: AuthManager(context.applicationContext).also { instance = it }
            }
        }
    }

    private val prefs: SharedPreferences =
        context.getSharedPreferences(PREF_NAME, Context.MODE_PRIVATE)

    /**
     * Save authentication state after successful login.
     */
    fun saveAuthState(
        authToken: String,
        userId: String,
        email: String? = null,
        displayName: String? = null
    ) {
        prefs.edit {
            putString(KEY_AUTH_TOKEN, authToken)
            putString(KEY_USER_ID, userId)
            putBoolean(KEY_IS_LOGGED_IN, true)
            putLong(KEY_LOGIN_TIMESTAMP, System.currentTimeMillis())
            email?.let { putString(KEY_USER_EMAIL, it) }
            displayName?.let { putString(KEY_USER_DISPLAY_NAME, it) }
        }
    }

    /**
     * Check if user is currently logged in and token hasn't expired.
     */
    fun isLoggedIn(): Boolean {
        val loggedIn = prefs.getBoolean(KEY_IS_LOGGED_IN, false)
        if (!loggedIn) return false

        val loginTimestamp = prefs.getLong(KEY_LOGIN_TIMESTAMP, 0L)
        val isTokenValid = (System.currentTimeMillis() - loginTimestamp) < TOKEN_EXPIRY_MS

        if (!isTokenValid) {
            // Token expired, clear state
            logout()
            return false
        }

        return getAuthToken() != null && getUserId() != null
    }

    /**
     * Retrieve the stored auth token.
     */
    fun getAuthToken(): String? {
        return prefs.getString(KEY_AUTH_TOKEN, null)
    }

    /**
     * Retrieve the stored user ID.
     */
    fun getUserId(): String? {
        return prefs.getString(KEY_USER_ID, null)
    }

    /**
     * Retrieve the stored user email.
     */
    fun getUserEmail(): String? {
        return prefs.getString(KEY_USER_EMAIL, null)
    }

    /**
     * Retrieve the stored display name.
     */
    fun getUserDisplayName(): String? {
        return prefs.getString(KEY_USER_DISPLAY_NAME, null)
    }

    /**
     * Update just the auth token (e.g., after a token refresh).
     */
    fun updateAuthToken(newToken: String) {
        prefs.edit {
            putString(KEY_AUTH_TOKEN, newToken)
            putLong(KEY_LOGIN_TIMESTAMP, System.currentTimeMillis())
        }
    }

    /**
     * Clear all auth data on logout.
     */
    fun logout() {
        prefs.edit {
            clear()
        }
    }

    /**
     * Get a data class representation of the current user session.
     */
    fun getCurrentSession(): UserSession? {
        if (!isLoggedIn()) return null

        return UserSession(
            authToken = getAuthToken() ?: return null,
            userId = getUserId() ?: return null,
            email = getUserEmail(),
            displayName = getUserDisplayName(),
            loginTimestamp = prefs.getLong(KEY_LOGIN_TIMESTAMP, 0L)
        )
    }
}

/**
 * Data class representing a user session.
 */
data class UserSession(
    val authToken: String,
    val userId: String,
    val email: String?,
    val displayName: String?,
    val loginTimestamp: Long
)

/**
 * Result sealed class for authentication operations.
 */
sealed class AuthResult {
    data class Success(val session: UserSession) : AuthResult()
    data class Error(val message: String, val exception: Exception? = null) : AuthResult()
}

